247	// PointerConfig generates the stub ignition for the machine to boot properly
248	// NOTE: If you change this, you also need to change the pointer configuration in openshift/installer, see
249	// https://github.com/openshift/installer/blob/master/pkg/asset/ignition/machine/node.go#L20
250	func PointerConfig(ignitionHost string, rootCA []byte) (ign3types.Config, error) {
251		configSourceURL := &url.URL{
252			Scheme: "https",
253			Host:   ignitionHost,
254			Path:   "/config/{{.Role}}",
255		}
256		// we do decoding here as curly brackets are escaped to %7B and breaks golang's templates
257		ignitionHostTmpl, err := url.QueryUnescape(configSourceURL.String())
258		if err != nil {
259			return ign3types.Config{}, err
260		}
261		CASource := dataurl.EncodeBytes(rootCA)
262		return ign3types.Config{
263			Ignition: ign3types.Ignition{
264				Version: ign3types.MaxVersion.String(),
265				Config: ign3types.IgnitionConfig{
266					Merge: []ign3types.Resource{{
267						Source: &ignitionHostTmpl,
268					}},
269				},
270				Security: ign3types.Security{
271					TLS: ign3types.TLS{
272						CertificateAuthorities: []ign3types.Resource{{
273							Source: &CASource,
274						}},
275					},
276				},
277			},
278		}, nil
279	}
