58	func GetIrreconcilableOverrides(mcopLister mcoplistersv1.MachineConfigurationLister) (*opv1.MachineConfiguration, error) {
59		mcop := opv1.MachineConfiguration{}
60		backoff := wait.Backoff{
61			Duration: 5 * time.Second,
62			Factor:   2,
63			Steps:    5,
64		}
65		if err := wait.ExponentialBackoff(backoff, func() (bool, error) {
66			mcopPtr, err := mcopLister.Get(MCOOperatorKnobsObjectName)
67			if err != nil {
68				klog.Warningf("Failed to fetch MachineConfiguration (will retry): %v", err)
69				return false, nil
70			}
71			mcop = *mcopPtr
72			return true, nil
73		}); err != nil {
74			return nil, fmt.Errorf("unable to fetch the MachineConfigurations object for MC validation: %w", err)
75		}
76	
77		return &mcop, nil
78	}
