80	// Parses a new config and determines if it is reconcilable.
81	func isReconcilable(oldIgn ign3types.Config, oldConfig, newConfig *mcfgv1.MachineConfig, overrides *opv1.IrreconcilableValidationOverrides) error {
82		newIgn, err := ParseAndConvertConfig(newConfig.Spec.Config.Raw)
83		if err != nil {
84			return fmt.Errorf("parsing new Ignition config from machineconfig %q failed: %w", newConfig.Name, err)
85		}
86	
87		// Check if this is a generally valid Ignition Config
88		if err := ValidateIgnition(newIgn); err != nil {
89			return fmt.Errorf("validating new Ignition config from machineconfig %q failed: %w", newConfig.Name, err)
90		}
91	
92		if err := isConfigReconcilable(oldIgn, newIgn, oldConfig, newConfig, overrides); err != nil {
93			return fmt.Errorf("new machineconfig %q is not reconcilable against %q: %s", oldConfig.Name, newConfig.Name, err)
94		}
95	
96		return nil
97	}
